"use client";

import Link from "next/link";
import { usePathname } from "next/navigation";
import { useState } from "react";
import { useAuth } from "../../context/AuthContext";

const sidebarStyles = {
  aside: {
    width: 250,
    minWidth: 250,
    background: "linear-gradient(180deg, #0d1b2a 0%, #1b263b 50%, #415a77 100%)",
    height: "calc(100vh - 80px - 40px)",
    marginTop: 80,
    position: "fixed" as const,
    left: 0,
    top: 0,
    color: "#fff",
    borderRight: "1px solid rgba(65,90,119,0.3)",
    boxShadow: "2px 0 10px rgba(0,0,0,0.2)",
    display: "flex",
    flexDirection: "column" as const,
    paddingTop: 20,
    overflow: "hidden",
    zIndex: 10,
  },
  menuContainer: {
    overflowY: "auto" as const,
    overflowX: "hidden" as const,
    flex: 1,
  },
  box: { padding: "2px", cursor: "pointer" },
  menuItem: (active: boolean) => ({
    display: "flex",
    alignItems: "center",
    gap: 12,
    padding: "12px 20px",
    color: active ? "#3b82f6" : "rgba(255,255,255,0.9)",
    textDecoration: "none",
    borderLeft: active ? "3px solid #3b82f6" : "3px solid transparent",
    background: active ? "rgba(59,130,246,0.15)" : "transparent",
    borderTopRightRadius: 20,
    borderBottomRightRadius: 20,
    transition: "all 0.2s",
  }),
  menuItemHover: {
    background: "linear-gradient(135deg, rgba(65,90,119,0.8), rgba(27,38,59,0.9))",
  },
  icon: { width: 20, fontSize: 18 },
  dropdown: {
    marginLeft: 20,
    marginTop: 4,
    display: "flex",
    flexDirection: "column" as const,
    gap: 2,
  },
  dropdownLink: (active: boolean) => ({
    padding: "8px 16px",
    color: active ? "#3b82f6" : "rgba(255,255,255,0.8)",
    textDecoration: "none",
    fontSize: 14,
    borderLeft: active ? "2px solid #3b82f6" : "2px solid transparent",
  }),
  tierBox: {
    background: "rgba(255,255,255,0.1)",
    color: "rgba(255,255,255,0.8)",
    padding: 10,
    textAlign: "center" as const,
    fontWeight: 700,
    fontSize: 14,
  },
  toggle: {
    padding: "10px 20px",
    color: "rgba(255,255,255,0.7)",
    cursor: "pointer",
    fontSize: 13,
    borderTop: "1px solid rgba(65,90,119,0.3)",
  },
  logout: {
    padding: "12px 20px",
    color: "#f87171",
    cursor: "pointer",
    display: "flex",
    alignItems: "center",
    gap: 12,
    borderTop: "1px solid rgba(65,90,119,0.3)",
  },
};

export default function AdminSidebar() {
  const pathname = usePathname();
  const { logout } = useAuth();
  const [menuLainOpen, setMenuLainOpen] = useState(false);

  const isActive = (path: string) => pathname === path || pathname.startsWith(path + "/");

  return (
    <aside style={sidebarStyles.aside}>
      <div style={sidebarStyles.menuContainer}>
        {/* Dashboard */}
        <div style={sidebarStyles.box}>
          <Link href="/admin" style={sidebarStyles.menuItem(isActive("/admin") && pathname === "/admin")}>
            <span style={sidebarStyles.icon}>🏠</span>
            <span>Dashboard</span>
          </Link>
        </div>

        {/* Aplikasi */}
        <div style={sidebarStyles.box}>
          <Link href="/admin/aplikasi" style={sidebarStyles.menuItem(isActive("/admin/aplikasi"))}>
            <span style={sidebarStyles.icon}>🪟</span>
            <span>Aplikasi</span>
          </Link>
        </div>

        {/* Permohonan Validasi */}
        <div style={sidebarStyles.box}>
          <Link href="#" style={sidebarStyles.menuItem(false)}>
            <span style={sidebarStyles.icon}>✉</span>
            <span>Permohonan Validasi</span>
          </Link>
        </div>

        {/* Referensi User */}
        <div style={sidebarStyles.box}>
          <div style={sidebarStyles.menuItem(isActive("/admin/referensi"))}>
            <span style={sidebarStyles.icon}>🔗</span>
            <span>Referensi User</span>
          </div>
          <div style={sidebarStyles.dropdown}>
            <Link href="/admin/referensi/pemutakhiran-ppat" style={sidebarStyles.dropdownLink(isActive("/admin/referensi/pemutakhiran-ppat"))}>
              Pemutakhiran Data PPAT
            </Link>
            <Link href="/admin/referensi/status-ppat" style={sidebarStyles.dropdownLink(isActive("/admin/referensi/status-ppat"))}>
              Status PPAT
            </Link>
            <Link href="/admin/referensi/validasi-qr" style={sidebarStyles.dropdownLink(isActive("/admin/referensi/validasi-qr"))}>
              Validasi QR
            </Link>
          </div>
        </div>

        {/* User Data */}
        <div style={sidebarStyles.box}>
          <div style={sidebarStyles.menuItem(isActive("/admin/data-user"))}>
            <span style={sidebarStyles.icon}>👤</span>
            <span>User Data</span>
          </div>
          <div style={sidebarStyles.dropdown}>
            <Link href="/admin/data-user/pending" style={sidebarStyles.dropdownLink(pathname === "/admin/data-user/pending")}>
              Verifikasi Data User
            </Link>
            <Link href="/admin/data-user/complete" style={sidebarStyles.dropdownLink(pathname === "/admin/data-user/complete")}>
              Data User
            </Link>
          </div>
        </div>

        {/* Users Group, Group Users, Group Privilege */}
        <div style={sidebarStyles.box}>
          <Link href="#" style={sidebarStyles.menuItem(false)}>
            <span style={sidebarStyles.icon}>🪪</span>
            <span>Users Group</span>
          </Link>
        </div>
        <div style={sidebarStyles.box}>
          <Link href="#" style={sidebarStyles.menuItem(false)}>
            <span style={sidebarStyles.icon}>👥</span>
            <span>Group Users</span>
          </Link>
        </div>
        <div style={sidebarStyles.box}>
          <Link href="#" style={sidebarStyles.menuItem(false)}>
            <span style={sidebarStyles.icon}>🔍</span>
            <span>Group Privilege</span>
          </Link>
        </div>

        {/* Menu Lain - PPAT, LTB, LSB, dll */}
        <div
          style={sidebarStyles.toggle}
          onClick={() => setMenuLainOpen(!menuLainOpen)}
          role="button"
          tabIndex={0}
          onKeyDown={(e) => e.key === "Enter" && setMenuLainOpen(!menuLainOpen)}
        >
          {menuLainOpen ? "▼" : "▶"} Menu Lain
        </div>

        {menuLainOpen && (
          <>
            <div style={sidebarStyles.tierBox}>PPAT</div>
            <div style={sidebarStyles.box}>
              <Link href="#" style={sidebarStyles.menuItem(false)}>
                <span style={sidebarStyles.icon}>📒</span>
                <span>Booking SSPD</span>
              </Link>
            </div>
            <div style={sidebarStyles.box}>
              <Link href="#" style={sidebarStyles.menuItem(false)}>
                <span style={sidebarStyles.icon}>📁</span>
                <span>Laporan Bulanan PPAT</span>
              </Link>
            </div>

            <div style={sidebarStyles.tierBox}>Loket Terima Berkas</div>
            <div style={sidebarStyles.box}>
              <Link href="#" style={sidebarStyles.menuItem(false)}>
                <span style={sidebarStyles.icon}>📂</span>
                <span>Terima Berkas SSPD</span>
              </Link>
            </div>

            <div style={sidebarStyles.tierBox}>Loket Serah Berkas</div>
            <div style={sidebarStyles.box}>
              <Link href="#" style={sidebarStyles.menuItem(false)}>
                <span style={sidebarStyles.icon}>✈</span>
                <span>Pelayanan Penyerahan SSPD</span>
              </Link>
            </div>

            <div style={sidebarStyles.tierBox}>Peneliti</div>
            <div style={sidebarStyles.box}>
              <Link href="#" style={sidebarStyles.menuItem(false)}>
                <span style={sidebarStyles.icon}>⚖</span>
                <span>Verifikasi SSPD</span>
              </Link>
            </div>

            <div style={sidebarStyles.tierBox}>BANK</div>
            <div style={sidebarStyles.box}>
              <Link href="#" style={sidebarStyles.menuItem(false)}>
                <span style={sidebarStyles.icon}>💰</span>
                <span>Transaksi Bank</span>
              </Link>
            </div>
          </>
        )}

        {/* FAQ */}
        <div style={sidebarStyles.box}>
          <Link href="/faq" style={sidebarStyles.menuItem(isActive("/faq"))}>
            <span style={sidebarStyles.icon}>❓</span>
            <span>FAQ</span>
          </Link>
        </div>
      </div>

      {/* Logout */}
      <div style={sidebarStyles.logout} onClick={logout} role="button" tabIndex={0} onKeyDown={(e) => e.key === "Enter" && logout()}>
        <span>🚪</span>
        <span>Log Out</span>
      </div>
    </aside>
  );
}
