"use client";

import Link from "next/link";
import { useAuth } from "../context/AuthContext";
import { useState, useEffect } from "react";

interface HeaderProps {
  /** Judul di header (mis. "Dashboard", "Data User") */
  title?: string;
}

export default function Header({ title = "Dashboard" }: HeaderProps) {
  const { user } = useAuth();
  const [foto, setFoto] = useState<string | null>(null);

  useEffect(() => {
    if (typeof window !== "undefined") setFoto(localStorage.getItem("foto"));
  }, [user]);

  return (
    <header
      style={{
        background: "linear-gradient(135deg, #0d1b2a 0%, #1b263b 50%, #415a77 100%)",
        height: 80,
        width: "100%",
        position: "fixed",
        top: 0,
        left: 0,
        display: "flex",
        justifyContent: "space-between",
        alignItems: "center",
        padding: "0 20px",
        boxShadow: "0 4px 20px rgba(0,0,0,0.2)",
        borderBottom: "1px solid rgba(65,90,119,0.3)",
        zIndex: 100,
        color: "#fff",
      }}
    >
      {/* Header left: logo, Bappenda, title */}
      <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
        <Link href="/admin" style={{ display: "flex", alignItems: "center" }}>
          <img src="/asset/Logo_image.svg" alt="Logo" style={{ width: 50, height: "auto" }} />
        </Link>
        <div style={{ display: "flex", flexDirection: "column", lineHeight: 1.2, marginRight: 10 }}>
          <span style={{ fontSize: 22, fontWeight: 700 }}>Bappenda</span>
          <span style={{ fontSize: 18, opacity: 0.9 }}>Kabupaten Bogor</span>
        </div>
        <img src="/asset/dekorasi_icon.png" alt="" style={{ width: 100, height: "auto", marginTop: 4 }} />
        <div
          style={{
            marginLeft: 16,
            paddingLeft: 16,
            borderLeft: "1px solid rgba(255,255,255,0.3)",
            fontSize: 18,
            fontWeight: 600,
          }}
        >
          {title}
        </div>
      </div>

      {/* Header right: profile, member */}
      <div style={{ display: "flex", alignItems: "center", gap: 20 }}>
        <div style={{ position: "relative" }}>
          <div
            style={{
              width: 44,
              height: 44,
              borderRadius: "50%",
              background: "rgba(255,255,255,0.15)",
              display: "flex",
              alignItems: "center",
              justifyContent: "center",
              cursor: "pointer",
              overflow: "hidden",
            }}
          >
            {foto ? (
              <img src={foto} alt="" style={{ width: "100%", height: "100%", objectFit: "cover" }} />
            ) : (
              <span style={{ fontSize: 20 }}>👤</span>
            )}
          </div>
          <Link
            href="/profile"
            style={{
              position: "absolute",
              top: "100%",
              right: 0,
              marginTop: 4,
              padding: "8px 12px",
              background: "#1b263b",
              borderRadius: 8,
              color: "#fff",
              textDecoration: "none",
              fontSize: 14,
              display: "block",
              boxShadow: "0 4px 12px rgba(0,0,0,0.3)",
            }}
          >
            Profil
          </Link>
        </div>
        <div
          style={{
            display: "flex",
            flexDirection: "column",
            alignItems: "center",
            color: "rgba(255,255,255,0.9)",
            fontSize: 12,
          }}
        >
          <span>member</span>
          <span style={{ fontWeight: 600, fontSize: 14 }}>{user?.nama || user?.userid || "—"}</span>
        </div>
      </div>
    </header>
  );
}
